#!/bin/bash
# ==============================================================================
# DO NOT EDIT THIS FILE
# This is an internal execution script called by submit.py.
# To change SLURM parameters or node configurations, use submit.py arguments.
# ==============================================================================
set -e

# Setup Paths & Environment
export nvhpc_path=/home/mog/nvhpc_24_9/Linux_x86_64/24.9
export HPCX_HOME=$nvhpc_path/comm_libs/12.6/hpcx/hpcx-2.20
export MY_PLUGIN_PATH=$HPCX_HOME/nccl_rdma_sharp_plugin/lib
export SHARP_LIB_PATH=$HPCX_HOME/sharp/lib

source $HPCX_HOME/hpcx-init.sh
export PATH=$HPCX_HOME/ompi/bin:$PATH
export LD_LIBRARY_PATH=$HPCX_HOME/ompi/lib:$HPCX_HOME/ucx/lib:$HPCX_HOME/sharp/lib:$MY_PLUGIN_PATH:$LD_LIBRARY_PATH

export OMP_NUM_THREADS=${SLURM_CPUS_PER_TASK:-1}

# Build Phase
CMAKE_PRESET_NAME="nano5"
BUILD_DIR="build"

if [ ! -f "$BUILD_DIR/CMakeCache.txt" ]; then
    cmake --preset $CMAKE_PRESET_NAME
fi
# cmake --build build -j32

# Snapshot Phase
CURRENT_DIR=$(pwd)
REPO_ROOT=$(git rev-parse --show-toplevel)
SNAPSHOT_DIR="$VVM_OUTPUT_DIR/code_snapshot"

rm -rf "$SNAPSHOT_DIR"
mkdir -p "$SNAPSHOT_DIR"

INCLUDE_PATHS=$(git -C "$REPO_ROOT" ls-tree --name-only HEAD | grep -vE "^(rundata|tests|docs|externals)$" | tr '\n' ' ')
git -C "$REPO_ROOT" archive HEAD $INCLUDE_PATHS | tar -x -C "$SNAPSHOT_DIR"

cd "$SNAPSHOT_DIR"
printf "rundata/\ntests/\ndocs/\nexternals/\nbuild/\nlog/\n" > .gitignore
git init -q
git add .
git -c user.name="Snapshot" -c user.email="snap@local" commit -q -m "Base: $(git -C "$REPO_ROOT" rev-parse HEAD)" || true
cd "$CURRENT_DIR"

rsync -a --exclude={'.git','build','log','rundata','tests','docs','externals','tags'} "$REPO_ROOT/" "$SNAPSHOT_DIR/"

cp "$VVM_CONFIG_FILE" "$SNAPSHOT_DIR/"
[ -f "$VVM_PROF_FILE" ] && cp "$VVM_PROF_FILE" "$SNAPSHOT_DIR/"
[ -f "$VVM_SPAT_FILE" ] && cp "$VVM_SPAT_FILE" "$SNAPSHOT_DIR/"

# Execution Phase
cd build

VVM_ARGS=""
if [ "$VVM_IO_ENGINE" == "SST" ]; then
    VVM_ARGS="--io-tasks $VVM_IO_TASKS"
fi

mpirun -np $VVM_TOTAL_TASKS \
 -x NCCL_DEBUG=INFO \
 -x HDF5_USE_FILE_LOCKING=FALSE \
 --mca io ompio \
 --mca sharedfp ^lockedfile,individual \
 ./vvm "$VVM_CONFIG_FILE" $VVM_ARGS
